public:
    __aicore__ inline KernelCumsumExclusiveCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength,
                                uint32_t axisLength,
                                uint32_t outerSize,
                                uint32_t tileLength,
                                int32_t dim)
